import React, { useState, useEffect, useRef, useCallback } from 'react';
import type { Order, OrderFormData } from '../types';
import { COUNTRIES, PRODUCTS, ORDER_STATUSES, CREATED_BY } from '../utils/constants';

interface Props {
  order?: Order | null;
  onSubmit: (data: OrderFormData) => Promise<void>;
  onClose: () => void;
}

type FormErrors = Partial<Record<keyof OrderFormData, string>>;

const EMPTY_FORM: OrderFormData = {
  firstName: '', lastName: '', email: '', phone: '',
  streetAddress: '', city: '', state: '', postalCode: '',
  country: 'United States', product: 'Fiber Internet 300 Mbps',
  quantity: 1, unitPrice: 0, status: 'Pending',
  createdBy: 'Mr. Michael Harris',
};

export const OrderForm: React.FC<Props> = ({ order, onSubmit, onClose }) => {
  const [errors, setErrors] = useState<FormErrors>({});
  const [submitting, setSubmitting] = useState(false);
  const [totalAmount, setTotalAmount] = useState(0);

  // Use refs for form values — no re-render on every keystroke!
  const formRef = useRef<OrderFormData>({ ...EMPTY_FORM });

  useEffect(() => {
    if (order) {
      const { id, orderId, orderDate, totalAmount: ta, createdAt, updatedAt, ...rest } = order;
      formRef.current = { ...rest } as OrderFormData;
      setTotalAmount(order.quantity * order.unitPrice);
    } else {
      formRef.current = { ...EMPTY_FORM };
      setTotalAmount(0);
    }
    setErrors({});
    // Force inputs to show values
    forceUpdateInputs();
  }, [order]);

  const forceUpdateInputs = () => {
    // Small timeout to let DOM render
    setTimeout(() => {
      const f = formRef.current;
      setField('firstName', f.firstName);
    }, 0);
  };

  const setField = useCallback((field: keyof OrderFormData, value: string | number) => {
    (formRef.current as any)[field] = value;
    if (field === 'quantity' || field === 'unitPrice') {
      const q = field === 'quantity' ? Number(value) : formRef.current.quantity;
      const p = field === 'unitPrice' ? Number(value) : formRef.current.unitPrice;
      setTotalAmount(q * p);
    }
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: undefined }));
    }
  }, [errors]);

  const validate = (): boolean => {
    const f = formRef.current;
    const mandatory: (keyof OrderFormData)[] = [
      'firstName', 'lastName', 'email', 'phone', 'streetAddress',
      'city', 'state', 'postalCode', 'country', 'product',
      'quantity', 'unitPrice', 'status', 'createdBy',
    ];
    const newErrors: FormErrors = {};
    mandatory.forEach(field => {
      const v = (f as any)[field];
      if (v === '' || v === null || v === undefined) {
        newErrors[field] = 'Please fill the field';
      }
    });
    if (f.quantity < 1) newErrors.quantity = 'Quantity cannot be less than 1';
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setSubmitting(true);
    try {
      await onSubmit({ ...formRef.current });
      onClose();
    } finally {
      setSubmitting(false);
    }
  };

  // Uncontrolled input — no lag!
  const Input = ({ field, type = 'text', placeholder, style = {} }: {
    field: keyof OrderFormData; type?: string; placeholder?: string; style?: React.CSSProperties;
  }) => (
    <input
      type={type}
      defaultValue={String((formRef.current as any)[field] ?? '')}
      onChange={e => setField(field, type === 'number' ? Number(e.target.value) : e.target.value)}
      placeholder={placeholder}
      style={{ ...inputStyle, ...(errors[field] ? errorStyle : {}), ...style }}
    />
  );

  const Select = ({ field, options }: { field: keyof OrderFormData; options: string[] }) => (
    <select
      defaultValue={String((formRef.current as any)[field])}
      onChange={e => setField(field, e.target.value)}
      style={{ ...inputStyle, ...(errors[field] ? errorStyle : {}) }}
    >
      {options.map(o => <option key={o} value={o}>{o}</option>)}
    </select>
  );

  const FieldWrap = ({ label, field, span = 1, children }: {
    label: string; field: keyof OrderFormData; span?: number; children: React.ReactNode;
  }) => (
    <div style={{ gridColumn: `span ${span}` }}>
      <label style={labelStyle}>{label}<span style={{ color: '#EF4444' }}> *</span></label>
      {children}
      {errors[field] && <p style={{ margin: '4px 0 0', fontSize: '12px', color: '#EF4444' }}>{errors[field]}</p>}
    </div>
  );

  return (
    <div style={overlayStyle} onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={modalStyle}>
        {/* Header */}
        <div style={headerStyle}>
          <div>
            <h2 style={{ margin: 0, fontSize: '20px', fontWeight: 700, color: '#111827' }}>
              {order ? 'Edit Order' : 'Create Order'}
            </h2>
            <p style={{ margin: '4px 0 0', fontSize: '13px', color: '#6B7280' }}>
              {order ? `Editing ${order.orderId}` : 'Fill in the details to create a new order'}
            </p>
          </div>
          <button onClick={onClose} style={closeBtnStyle}>✕</button>
        </div>

        <form onSubmit={handleSubmit} noValidate>
          <div style={bodyStyle}>
            {/* Customer Information */}
            <div style={{ marginBottom: '1.75rem' }}>
              <div style={sectionHeaderStyle}>
                <div style={{ ...dotStyle, background: '#10B981' }} />
                <h3 style={sectionTitleStyle}>Customer Information</h3>
              </div>
              <div style={gridStyle}>
                <FieldWrap label="First name" field="firstName">
                  <Input field="firstName" placeholder="Enter first name" />
                </FieldWrap>
                <FieldWrap label="Last name" field="lastName">
                  <Input field="lastName" placeholder="Enter last name" />
                </FieldWrap>
                <FieldWrap label="Email ID" field="email">
                  <Input field="email" type="email" placeholder="Enter email id" />
                </FieldWrap>
                <FieldWrap label="Phone number" field="phone">
                  <Input field="phone" placeholder="Enter phone number" />
                </FieldWrap>
                <FieldWrap label="Street address" field="streetAddress" span={2}>
                  <Input field="streetAddress" placeholder="Enter street address" />
                </FieldWrap>
                <FieldWrap label="City" field="city">
                  <Input field="city" placeholder="Enter city" />
                </FieldWrap>
                <FieldWrap label="State / Province" field="state">
                  <Input field="state" placeholder="Enter state / province" />
                </FieldWrap>
                <FieldWrap label="Postal code" field="postalCode">
                  <Input field="postalCode" placeholder="Enter postal code" />
                </FieldWrap>
                <FieldWrap label="Country" field="country">
                  <Select field="country" options={COUNTRIES} />
                </FieldWrap>
              </div>
            </div>

            {/* Order Information */}
            <div style={{ marginBottom: '1.75rem' }}>
              <div style={sectionHeaderStyle}>
                <div style={{ ...dotStyle, background: '#8B5CF6' }} />
                <h3 style={sectionTitleStyle}>Order Information</h3>
              </div>
              <div style={gridStyle}>
                <FieldWrap label="Choose product" field="product">
                  <Select field="product" options={PRODUCTS} />
                </FieldWrap>
                <FieldWrap label="Status" field="status">
                  <Select field="status" options={ORDER_STATUSES} />
                </FieldWrap>
                <FieldWrap label="Quantity" field="quantity">
                  <input
                    type="number" min={1}
                    defaultValue={formRef.current.quantity}
                    onChange={e => setField('quantity', Math.max(1, Number(e.target.value)))}
                    style={{ ...inputStyle, ...(errors.quantity ? errorStyle : {}) }}
                  />
                </FieldWrap>
                <FieldWrap label="Unit price" field="unitPrice">
                  <div style={{ position: 'relative' }}>
                    <span style={{ position: 'absolute', left: '0.75rem', top: '50%', transform: 'translateY(-50%)', color: '#6B7280' }}>$</span>
                    <input
                      type="number" min={0} step={0.01}
                      defaultValue={formRef.current.unitPrice}
                      onChange={e => setField('unitPrice', Number(e.target.value))}
                      style={{ ...inputStyle, paddingLeft: '2rem', ...(errors.unitPrice ? errorStyle : {}) }}
                    />
                  </div>
                </FieldWrap>

                {/* Total Amount - read only */}
                <div>
                  <label style={labelStyle}>Total amount <span style={{ color: '#EF4444' }}>*</span></label>
                  <div style={readOnlyStyle}>
                    <span style={{ fontSize: '13px', color: '#6B7280' }}>Auto-calculated</span>
                    <span style={{ fontWeight: 600, fontSize: '16px', color: '#111827' }}>
                      ${totalAmount.toLocaleString('en-US', { minimumFractionDigits: 2 })}
                    </span>
                  </div>
                </div>

                <FieldWrap label="Created by" field="createdBy">
                  <Select field="createdBy" options={CREATED_BY} />
                </FieldWrap>
              </div>
            </div>
          </div>

          {/* Footer */}
          <div style={footerStyle}>
            <button type="button" onClick={onClose} style={cancelBtnStyle}>Cancel</button>
            <button type="submit" disabled={submitting} style={submitBtnStyle}>
              {submitting ? 'Saving...' : order ? 'Update Order' : 'Create Order'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const inputStyle: React.CSSProperties = {
  width: '100%', padding: '0.55rem 0.75rem',
  border: '1.5px solid #E5E7EB', borderRadius: '8px',
  fontSize: '14px', color: '#111827', background: '#FAFAFA',
  outline: 'none', boxSizing: 'border-box',
};
const errorStyle: React.CSSProperties = { borderColor: '#EF4444', background: '#FFF5F5' };
const labelStyle: React.CSSProperties = { display: 'block', fontSize: '13px', fontWeight: 500, color: '#374151', marginBottom: '6px' };
const overlayStyle: React.CSSProperties = { position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center', zIndex: 1000, padding: '1rem', backdropFilter: 'blur(2px)' };
const modalStyle: React.CSSProperties = { background: '#fff', borderRadius: '16px', width: '100%', maxWidth: '760px', maxHeight: '90vh', display: 'flex', flexDirection: 'column', boxShadow: '0 25px 60px rgba(0,0,0,0.15)' };
const headerStyle: React.CSSProperties = { padding: '1.5rem 2rem', borderBottom: '1px solid #F3F4F6', display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexShrink: 0 };
const closeBtnStyle: React.CSSProperties = { background: 'none', border: 'none', fontSize: '18px', cursor: 'pointer', color: '#9CA3AF' };
const bodyStyle: React.CSSProperties = { padding: '1.5rem 2rem', overflowY: 'auto', flex: 1 };
const sectionHeaderStyle: React.CSSProperties = { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '1rem' };
const dotStyle: React.CSSProperties = { width: '8px', height: '8px', borderRadius: '50%', flexShrink: 0 };
const sectionTitleStyle: React.CSSProperties = { margin: 0, fontSize: '14px', fontWeight: 600, color: '#374151', textTransform: 'uppercase', letterSpacing: '0.05em' };
const gridStyle: React.CSSProperties = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' };
const readOnlyStyle: React.CSSProperties = { padding: '0.55rem 0.75rem', border: '1.5px solid #E5E7EB', borderRadius: '8px', background: '#F9FAFB', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const footerStyle: React.CSSProperties = { padding: '1rem 2rem', borderTop: '1px solid #F3F4F6', display: 'flex', justifyContent: 'flex-end', gap: '0.75rem', flexShrink: 0 };
const cancelBtnStyle: React.CSSProperties = { padding: '0.6rem 1.5rem', borderRadius: '8px', border: '1.5px solid #E5E7EB', background: '#fff', color: '#374151', fontSize: '14px', fontWeight: 500, cursor: 'pointer' };
const submitBtnStyle: React.CSSProperties = { padding: '0.6rem 1.5rem', borderRadius: '8px', border: 'none', background: 'linear-gradient(135deg, #10B981 0%, #059669 100%)', color: '#fff', fontSize: '14px', fontWeight: 600, cursor: 'pointer' };
